import{_ as o,c as l,o as i,ag as a}from"./chunks/framework.DVUBUV_u.js";const p=JSON.parse('{"title":"История релизов","description":"","frontmatter":{"title":"История релизов"},"headers":[],"relativePath":"ru/releases/history.md","filePath":"ru/releases/history.md"}'),d={name:"ru/releases/history.md"};function c(r,e,t,s,n,h){return i(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="история-релизов" tabindex="-1">История релизов <a class="header-anchor" href="#история-релизов" aria-label="Permalink to &quot;История релизов&quot;">​</a></h1><h2 id="_2-0-0-2026-01-23" tabindex="-1">[2.0.0] - 2026-01-23 <a class="header-anchor" href="#_2-0-0-2026-01-23" aria-label="Permalink to &quot;[2.0.0] - 2026-01-23&quot;">​</a></h2><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li>Добавлена поддержка корпоративной версии приложения, не требующей установки.</li><li>Добавлена система отслеживания версий и уведомлений о доступности новых обновлений.</li><li>Проект переведён в формат <code>iframe</code> и больше не использует <code>popup</code> как точку входа.</li></ul><hr><h3 id="производительность" tabindex="-1">Производительность <a class="header-anchor" href="#производительность" aria-label="Permalink to &quot;Производительность&quot;">​</a></h3><ul><li>Решена проблема мгновенной утечки памяти на статичных сайтах, включая <code>Docusaurus</code> и <code>Hugo</code>.</li></ul><hr><h3 id="ui-ux" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><ul><li>Проведён рефакторинг стилей и общего визуального оформления продукта.</li></ul><h2 id="_2-1-0-2026-02-02" tabindex="-1">[2.1.0] - 2026-02-02 <a class="header-anchor" href="#_2-1-0-2026-02-02" aria-label="Permalink to &quot;[2.1.0] - 2026-02-02&quot;">​</a></h2><h3 id="core-1" tabindex="-1">Core <a class="header-anchor" href="#core-1" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li>Добавлена новая вкладка управления — <code>Network</code>.</li><li>Проведён редизайн приложения с учётом нового расположения в <code>iframe</code> вместо <code>popup</code>: на экране теперь доступно больше полезной информации.</li><li>Скорректирована вёрстка блоков <code>JSON</code> — блок отображается на всю высоту приложения.</li><li>Исправлено залипание вкладок при раннем открытии приложения: ранее для отображения вкладок <code>Props</code> и <code>Pinia</code> требовалась полная перезагрузка страницы.</li></ul><hr><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Исправлена ошибка, при которой избранные элементы <code>Props</code> не находились после обновления страницы или повторного прохождения сценариев.</li><li>Оптимизирована работа с <code>Props</code> для длительных сессий без избыточной нагрузки на CPU, проведён рефакторинг внутренней логики.</li><li>Переработана вкладка <code>Props</code>: улучшена работа с большим количеством объектов и поиск при наведении.</li><li>Из вкладки <code>Props</code> удалён режим <code>Props only</code>.</li></ul><hr><h3 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>Добавлен перехват всех вызовов <code>fetch</code> и <code>XMLHttpRequest</code>, за исключением запросов типа <code>OPTIONS</code> и запросов, инициированных расширением.</li><li>Добавлено отображение сводной информации по запросам: статус, метод, имя, время выполнения, размер.</li><li>Добавлен подробный просмотр запроса с разделами: параметры, авторизация, заголовки, запрос, ответ. Отображаются только заголовки, доступные в рамках <code>CORS</code>-ограничений браузера.</li><li>Добавлена возможность приостановки и возобновления записи запросов. Запись включена по умолчанию при первом открытии приложения.</li><li>Добавлен <code>Breakpoint</code> — остановка и модификация исходящего запроса перед отправкой.</li><li>Добавлен <code>Mock Response</code> — перехват заранее выбранного запроса с подменой ответа.</li><li>Добавлено быстрое копирование в буфер обмена URL-адресов, токенов и ключевых элементов.</li><li>Добавлена очистка всех записанных запросов одной кнопкой.</li><li>Реализована событийная архитектура без <code>polling</code> для минимального использования CPU.</li><li>Добавлено автоматическое определение двоичного содержимого — для таких данных отображаются только метаданные.</li></ul><h2 id="_2-2-0-2026-02-24" tabindex="-1">[2.2.0] - 2026-02-24 <a class="header-anchor" href="#_2-2-0-2026-02-24" aria-label="Permalink to &quot;[2.2.0] - 2026-02-24&quot;">​</a></h2><h3 id="core-2" tabindex="-1">Core <a class="header-anchor" href="#core-2" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li><p>Добавлена настройка <code>Display Mode</code> с возможностью переноса приложения во вкладку <code>DevTools</code> и отключения <code>overlay</code>-режима.</p></li><li><p>Проведён рефакторинг вкладки <code>Options</code> — настройки разбиты на логические разделы.</p></li><li><p>Изменена логика работы активных фильтров на вкладках <code>Props</code>, <code>Pinia Store</code> и <code>Network</code>: редактирование набора фильтров теперь доступно без перехода в настройки.</p></li><li><p>Исправлена область нажатия (<code>click area</code>) в текстовом режиме отображения <code>JSON</code>.</p></li><li><p>Большие <code>JSON</code> больше не обрезаются: для сохранения производительности при отображении отключаются CSS-стили.</p></li><li><p>Обновлена логика уведомления о новых версиях:</p><ul><li><code>Dismiss</code> переименована в <code>Later</code>;</li><li><code>Download</code> переименована в <code>Preview</code> и ведёт в <code>Options → About</code>;</li><li>добавлен блок с деталями версии и кнопками <code>Ignore</code> и <code>Download</code>.</li></ul></li></ul><hr><h3 id="props-1" tabindex="-1">Props <a class="header-anchor" href="#props-1" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Исправлена ошибка отсутствия подсветки UI-элементов <code>Props</code> в режиме <code>Standalone</code>.</li></ul><hr><h3 id="network-1" tabindex="-1">Network <a class="header-anchor" href="#network-1" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li><p>Добавлена поддержка <code>form-data</code> для чтения и подмены трафика.</p></li><li><p>Добавлена возможность сохранять используемые файлы для повторного использования при работе с <code>Breakpoint</code> и <code>form-data</code>.</p></li><li><p>Добавлены режимы <code>Rewrite Breakpoint</code> и <code>Rewrite Mock</code>: при наличии существующего перехвата предлагается перезаписать правило вместо создания нового.</p></li><li><p>Добавлена индикация активных <code>Breakpoint</code> и <code>Mock</code> для запроса; переход по счётчику открывает соответствующий раздел настроек.</p></li><li><p>Добавлен поиск по статус-коду ответа.</p></li><li><p>Расширены возможности <code>Breakpoint</code> — добавлен учёт HTTP-метода при перехвате.</p></li><li><p>Исправлена ошибка, при которой инспектор не открывался при срабатывании <code>Breakpoint</code>.</p></li><li><p>В контекстное меню запроса добавлены действия:</p><ul><li><code>Disable / Enable Breakpoint</code></li><li><code>Disable / Enable Mock</code></li><li><code>Delete Breakpoint / Mock</code></li><li>пункты отображаются только при наличии соответствующего правила.</li></ul></li></ul><hr><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><h4 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h4><ul><li>Базовые настройки приложения (<code>Display Mode</code>, <code>Search Parameters</code>, <code>Auto Refresh</code>, <code>JSON Editor Mode</code>) перенесены в отдельный раздел.</li><li>Управление файлом настроек (<code>Settings Management</code>) перенесено из шапки вкладки.</li></ul><h4 id="network-2" tabindex="-1">Network <a class="header-anchor" href="#network-2" aria-label="Permalink to &quot;Network&quot;">​</a></h4><ul><li><code>Search Settings</code> вынесены в отдельный раздел и стали независимыми.</li><li>Скорректирована вёрстка таблиц <code>Breakpoints</code> и <code>Mocks</code> — данные больше не растягиваются.</li><li>Добавлена возможность отключения и редактирования ранее созданных правил.</li></ul><h4 id="props-2" tabindex="-1">Props <a class="header-anchor" href="#props-2" aria-label="Permalink to &quot;Props&quot;">​</a></h4><ul><li>Управление файлом настроек перенесено в раздел.</li><li><code>Component Blacklist</code> перенесён из общего блока настроек.</li><li><code>Favorite Components</code> перенесены из общего блока настроек.</li></ul><h4 id="pinia-store" tabindex="-1">Pinia Store <a class="header-anchor" href="#pinia-store" aria-label="Permalink to &quot;Pinia Store&quot;">​</a></h4><ul><li>Управление файлом настроек перенесено в раздел.</li></ul><h4 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h4><ul><li><p>Добавлены кнопки <code>Release notes</code> и <code>Check for updates</code> (доступно только в <code>extension</code>-версии).</p></li><li><p>При наличии новой версии:</p><ul><li><code>Ignore</code> отключает повторные уведомления для текущей версии; состояние сбрасывается после выхода более новой версии.</li><li><code>Download</code> инициирует загрузку архива с приложением.</li></ul></li></ul><h2 id="_2-3-0-2026-03-16" tabindex="-1">[2.3.0] - 2026-03-16 <a class="header-anchor" href="#_2-3-0-2026-03-16" aria-label="Permalink to &quot;[2.3.0] - 2026-03-16&quot;">​</a></h2><h3 id="network-3" tabindex="-1">Network <a class="header-anchor" href="#network-3" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>Добавлена генерация <strong>Postman</strong>-коллекций на основе запросов, собранных во вкладке <code>Network</code>.</li><li>В однопанельном режиме кнопка <code>Copy cURL</code> заменена контекстным меню с доступом к: <ul><li><code>Breakpoint</code></li><li><code>Mock</code></li><li><code>Copy cURL</code></li></ul></li><li>Добавлена логика вызова контекстного меню (ПКМ) по шапке детализации запроса.</li></ul><hr><h3 id="props-3" tabindex="-1">Props <a class="header-anchor" href="#props-3" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Исправлена работа избранного и чёрного списка при работе с <code>Props</code>.</li><li>Изменена логика сбора данных с учетом <code>blacklist</code>: игнорируемые элементы исключаются на этапе предварительного обхода, а не только скрываются из таблицы, что ускоряет загрузку вкладки.</li><li>Добавлено меню быстрых действий для <code>Props</code>.</li><li>Добавлена возможность обновления открытого компонента в режиме чтения.</li><li>Добавлены shortcut-переходы к списку избранного при нажатии на счётчик избранных элементов.</li></ul><hr><h3 id="store" tabindex="-1">Store <a class="header-anchor" href="#store" aria-label="Permalink to &quot;Store&quot;">​</a></h3><ul><li>Добавлен функционал избранного для <code>Pinia Store</code> включая shortcut-переход.</li><li>Добавлено меню быстрых действий для <code>Pinia Store</code>.</li><li>Добавлена возможность обновления открытого элемента в режиме чтения.</li><li>В разделе <code>Options</code> доступно создание и редактирование пользовательских избранных элементов, включая поддержку <code>wildcards</code>.</li></ul><hr><h3 id="options-1" tabindex="-1">Options <a class="header-anchor" href="#options-1" aria-label="Permalink to &quot;Options&quot;">​</a></h3><ul><li>Изменён алгоритм хранения пользовательских настроек: выбранные файлы теперь сохраняются как локальные копии в хранилище приложения.</li><li><code>Standalone</code>-версия переведена на собственное локальное хранилище. Настройки сохраняются между запусками и доступны на разных сайтах без потери данных.</li><li>Режим tree временно отключён — работа с JSON доступна только в text-режиме.</li></ul><h4 id="customize" tabindex="-1">Customize <a class="header-anchor" href="#customize" aria-label="Permalink to &quot;Customize&quot;">​</a></h4><p>В разделе <code>Options → General → Customize</code> добавлены настройки визуального оформления приложения:</p><ul><li><code>Dark / Light</code> — цветовая схема;</li><li><code>Image</code> — фон (<code>File / Link</code>) с поддержкой: <ul><li>статичных изображений,</li><li><code>GIF</code>,</li><li><code>MP4</code>;</li></ul></li><li>Выбор файла через <code>Browse</code> или из списка ранее сохранённых;</li><li>Добавление файла по ссылке;</li><li><code>Image Opacity</code> — прозрачность;</li><li><code>Blur</code> — размытие;</li><li><code>Noise Intensity / Opacity</code> — параметры шумового слоя;</li><li><code>Position (X / Y)</code> — положение изображения;</li><li><code>Scale</code> — масштаб (<code>100–200%</code>).</li></ul><hr><h3 id="ui-ux-1" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux-1" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><ul><li>Добавлена адаптивная раскладка интерфейса для небольших экранов.</li><li>На широких экранах используется двухпанельный режим: список и детали отображаются одновременно.</li><li>При ширине около <code>1000px</code> интерфейс автоматически переключается в однопанельный режим.</li><li>Добавлена поддержка клавиши <code>Esc</code> для закрытия активных панелей и диалогов.</li><li>Добавлена поддержка поиска <code>Ctrl+F</code> в режиме вкладки <code>DevTools</code>.</li><li>Добавлены скелетоны загрузки для таблиц <code>Props</code> и <code>Pinia</code> вместо текста <code>Not found</code>.</li><li>Добавлены настройки отображения колонок для таблиц <code>Props</code>, <code>Pinia</code> и <code>Network</code>.</li><li>Изменён дизайн шеврона для открытия <code>iframe</code>.</li><li>Добавлена поддержка контекстного меню (ПКМ) при работе с таблицами.</li></ul><hr><h3 id="производительность-1" tabindex="-1">Производительность <a class="header-anchor" href="#производительность-1" aria-label="Permalink to &quot;Производительность&quot;">​</a></h3><ul><li>Изменена логика обработки <code>blacklist</code> во вкладке <code>Props</code>: заблокированные элементы больше не участвуют в предварительном обходе, что ускоряет сбор данных и загрузку вкладки.</li></ul><hr><h3 id="исправления" tabindex="-1">Исправления <a class="header-anchor" href="#исправления" aria-label="Permalink to &quot;Исправления&quot;">​</a></h3><ul><li>Исправлена область нажатия для блока <code>JSON</code> при редактировании во время скролла.</li><li>Исправлены зависания приложения при длительной работе вкладки <code>Network</code>.</li><li>Исправлено поведение <code>Ctrl+A</code> — выделение применяется только к активному полю ввода.</li><li>Исправлено отображение кнопок сброса и удаления в <code>disabled</code>-состоянии.</li><li>Исправлено отображение таблиц в <code>Options</code> при большом количестве значений.</li><li>Исправлены стили режима редактирования <code>JSON</code>.</li><li>Внесены косметические правки оформления.</li></ul><h2 id="_2-4-0-2026-04-19" tabindex="-1">[2.4.0] - 2026-04-19 <a class="header-anchor" href="#_2-4-0-2026-04-19" aria-label="Permalink to &quot;[2.4.0] - 2026-04-19&quot;">​</a></h2><h3 id="network-4" tabindex="-1">Network <a class="header-anchor" href="#network-4" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>При установке паузы, перехватчики инспектора теперь снимаются, в стандартных Devtools будет отображаться оригинальный инициатор вместо injected.ts.</li><li>Таблица <code>Network</code> переведена на виртуализацию для ускорения работы и снижения фризов.</li><li>Изменено стартовое окно при открытии детализации запроса — по умолчанию теперь открывается <code>Response</code>.</li><li>При срабатывании <code>Breakpoint</code> остановленный метод автоматически открывается на вкладке <code>Request</code>.</li><li>В списках <code>Search by</code> на вкладке <code>Network</code> и в разделе <code>Options</code> добавлена поддержка поиска по колонке <code>Name</code>.</li></ul><hr><h3 id="props-4" tabindex="-1">Props <a class="header-anchor" href="#props-4" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li><p>Значительно ускорена работа с <code>Props</code>, что позволяет безопасно использовать автообновление данных.</p></li><li><p>В таблице <code>Props</code> колонка <code>Props</code> заменена на <code>Passed</code> и <code>Declared</code> (все колонки доступны для скрытия):</p><ul><li><code>Passed</code> — количество <code>Props</code>, полученных в текущий момент.</li><li><code>Declared</code> — количество возможных <code>Props</code>, объявленных для элемента.</li></ul></li><li><p>В правом блоке детализации <code>Props</code> данные разделены на две вкладки:</p><ul><li><code>Passed</code> — фактически переданные <code>Props</code> (открывается по умолчанию).</li><li><code>Declared</code> — все <code>Props</code>, объявленные компонентом.</li></ul></li><li><p>В блоке <code>Details Props</code> добавлен параметр <code>Size</code>.</p></li></ul><h4 id="inspect-props-inspector" tabindex="-1">Inspect (<code>Props Inspector</code>) <a class="header-anchor" href="#inspect-props-inspector" aria-label="Permalink to &quot;Inspect (`Props Inspector`)&quot;">​</a></h4><ul><li>Добавлен режим выбора элементов на странице по аналогии с <code>Chrome DevTools Elements</code>.</li><li>Позволяет выбрать элемент прямо на странице и быстро отфильтровать список <code>Props</code>.</li><li>Подсвечивает <code>Vue</code>-компоненты при наведении.</li><li>Показывает краткую информацию об элементе: <code>Name</code>, <code>Root element</code>, <code>Received Props</code>, <code>Nested components</code>.</li><li>После выбора отображает <code>Props</code> только выбранного элемента и его вложенных компонентов.</li><li>Фильтр можно быстро сбросить через бейдж <code>Filtered</code>.</li></ul><hr><h3 id="ui-ux-2" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux-2" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><h4 id="оконныи-режим" tabindex="-1">Оконный режим <a class="header-anchor" href="#оконныи-режим" aria-label="Permalink to &quot;Оконный режим&quot;">​</a></h4><ul><li>Добавлена поддержка оконного режима приложения с сохранением выбранного положения для обеих версий запуска.</li><li>Обновлён шеврон открытия <code>iframe</code> — добавлена иконка перетаскивания.</li><li>Добавлена возможность закрепления шеврона по любой из четырёх сторон браузера с автоматическим растягиванием окна приложения по высоте.</li></ul><h4 id="настроики-автозапуска" tabindex="-1">Настройки автозапуска <a class="header-anchor" href="#настроики-автозапуска" aria-label="Permalink to &quot;Настройки автозапуска&quot;">​</a></h4><ul><li><p>Добавлена возможность задать список сайтов для автоматического запуска приложения (<code>Whitelist</code>) и список исключений, где запуск приложения и отображение шеврона запрещены (<code>Blacklist</code>).</p></li><li><p>Добавлено <code>popup</code>-меню расширения с быстрыми действиями:</p><ul><li><code>Forced Launch</code> - Принудительный запуск приложения (игнорирует ограничения white и blacklist site, а так же внутреннее ограничение на статичные сайты);</li><li><code>Reset Settings</code> - Сброс всех настроек расширения.</li></ul></li></ul><h4 id="прочие-улучшения-интерфеиса" tabindex="-1">Прочие улучшения интерфейса <a class="header-anchor" href="#прочие-улучшения-интерфеиса" aria-label="Permalink to &quot;Прочие улучшения интерфейса&quot;">​</a></h4><ul><li>Исправлены стили <code>JSON</code> для больших объёмов данных.</li><li>Добавлена возможность точного поиска при вводе значения в кавычках: без кавычек поиск работает в режиме <code>like</code>.</li><li>Внесены мелкие визуальные правки интерфейса.</li><li>Доработана логика закрытия вкладок по клавише <code>Esc</code> в режиме <code>DevTools</code>: сначала выполняется выход из вкладок, а если закрывать больше нечего — открывается консоль <code>DevTools</code>.</li></ul><hr><h3 id="производительность-2" tabindex="-1">Производительность <a class="header-anchor" href="#производительность-2" aria-label="Permalink to &quot;Производительность&quot;">​</a></h3><ul><li>Изменён механизм определения <code>Props</code> и <code>Store</code> — получение данных значительно ускорено.</li><li>Увеличены лимиты на максимальное количество вычитываемых <code>Props</code>.</li><li>Проведён рефакторинг внутренней структуры проекта: удалены неиспользуемые модули, мёртвый код и дублирующая логика.</li></ul><hr><h3 id="документация" tabindex="-1">Документация <a class="header-anchor" href="#документация" aria-label="Permalink to &quot;Документация&quot;">​</a></h3><ul><li>У проекта появилась полноценная документация.</li><li>На лендинговой странице добавлен раздел <code>Documentation</code>.</li><li>В разделе <code>Options → About</code> добавлен быстрый переход к документации.</li></ul><hr><h3 id="исправления-1" tabindex="-1">Исправления <a class="header-anchor" href="#исправления-1" aria-label="Permalink to &quot;Исправления&quot;">​</a></h3><ul><li>Заблокирована работа стандартного ПКМ внутри контекстного меню приложения.</li><li>Исправлено ложное определение избранного в детализации Props при совпадении имен.</li><li>Доработана логика работы поиска для Devtools mode. Исправлен кейс, когда поиск мог перестать работать, добавлена логика сброса подсветки при очистке поля или закрытия функционала поиска.</li></ul>',89)])])}const P=o(d,[["render",c]]);export{p as __pageData,P as default};
